## Step 4: DLQ replay endpoint

```java
@RestController
@RequestMapping("/admin/dlq")
@PreAuthorize("hasRole('ADMIN')")
@RequiredArgsConstructor
public class DlqReplayController {

    private final DlqMessageRepository dlqRepo;
    private final KafkaTemplate<String, String> kafka;

    // Replay single message after fixing the root cause
    @PostMapping("/replay/{id}")
    public ResponseEntity<Void> replay(@PathVariable Long id) {
        DlqMessage dlqMsg = dlqRepo.findById(id).orElseThrow();

        // Re-publish to original topic
        kafka.send(dlqMsg.getOriginalTopic(), dlqMsg.getPayload());

        dlqMsg.setStatus(DlqStatus.REPLAYED);
        dlqMsg.setReplayedAt(Instant.now());
        dlqRepo.save(dlqMsg);

        log.info("DLQ message {} replayed to topic {}", id, dlqMsg.getOriginalTopic());
        return ResponseEntity.ok().build();
    }

    // Replay all PENDING_REVIEW messages for a topic
    @PostMapping("/replay-all")
    public ResponseEntity<Map<String, Integer>> replayAll(
            @RequestParam String topic) {
        List<DlqMessage> pending = dlqRepo
            .findByOriginalTopicAndStatus(topic, DlqStatus.PENDING_REVIEW);

        int replayed = 0;
        for (DlqMessage msg : pending) {
            try {
                kafka.send(msg.getOriginalTopic(), msg.getPayload());
                msg.setStatus(DlqStatus.REPLAYED);
                dlqRepo.save(msg);
                replayed++;
            } catch (Exception e) {
                log.error("Failed to replay DLQ message {}: {}", msg.getId(), e.getMessage());
            }
        }

        log.info("Replayed {}/{} DLQ messages for topic {}", replayed, pending.size(), topic);
        return ResponseEntity.ok(Map.of("replayed", replayed, "total", pending.size()));
    }
}
```

