    return RetryInterceptorBuilder.stateless()
        .maxAttempts(3)
        .backOffOptions(1000L, 2.0, 10000L)  // 1s, 2s, 4s
        .recoverer(new RejectAndDontRequeueRecoverer())  // nack → goes to DLX
        .build();
